interface LogoItem {
  id: string;
  name: string;
  icon: React.ReactNode;
  color: string;
  x: number;
  y: number;
  size: number;
  speedX: number;
  speedY: number;
}

export default function TechConstellation() {
  const [logos, setLogos] = useState<LogoItem[]>([]);
  const [visibleLogos, setVisibleLogos] = useState<Set<string>>(new Set());
  const logosRef = useRef<LogoItem[]>([]);
  const animationRef = useRef<number | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Initialize logos
  useEffect(() => {
    const techEntries = Object.entries(techLogos);
    const initialLogos: LogoItem[] = [];
    
    // Create 50 logos scattered across a tall area
    for (let i = 0; i < 50; i++) {
      const [name, data] = techEntries[Math.floor(Math.random() * techEntries.length)];
      initialLogos.push({
        id: `${name}-${i}`,
        name,
        icon: data.svg,
        color: data.color,
        x: Math.random() * 100, // percentage across width
        y: Math.random() * 500, // percentage down height (500% = 5x viewport)
        size: 24 + Math.random() * 32, // 24-56px
        speedX: (Math.random() - 0.5) * 0.008, // very slow drift
        speedY: (Math.random() - 0.5) * 0.005,
      });
    }
    
    setLogos(initialLogos);
    logosRef.current = initialLogos;
  }, []);

  // Scroll-based visibility detection
  useEffect(() => {
    const handleScroll = () => {
      const scrollY = window.scrollY;
      const windowHeight = window.innerHeight;
      const viewportCenter = scrollY + windowHeight / 2;
      
      const newVisible = new Set<string>();
      
      logosRef.current.forEach((logo) => {
        // Calculate logo position in pixels
        const logoY = (logo.y / 100) * (windowHeight * 5); // 5x viewport height
        const distance = Math.abs(logoY - viewportCenter);
        
        // Logo becomes visible (colored) when within viewport range
        if (distance < windowHeight * 0.9) {
          newVisible.add(logo.id);
        }
      });
      
      setVisibleLogos(newVisible);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    handleScroll(); // Initial check
    
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Animation loop for slow drift
  useEffect(() => {
    const animate = () => {
      logosRef.current = logosRef.current.map(logo => {
        let newX = logo.x + logo.speedX;
        let newY = logo.y + logo.speedY;

        // Wrap around edges
        if (newX < -10) newX = 110;
        if (newX > 110) newX = -10;
        if (newY < -10) newY = 510;
        if (newY > 510) newY = -10;

        return { ...logo, x: newX, y: newY };
      });

      setLogos([...logosRef.current]);
      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, []);

  return (
    <div
      ref={containerRef}
      style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        height: '500vh', // 5x viewport height
        pointerEvents: 'none',
        zIndex: 0,
        overflow: 'hidden',
      }}
    >
      {logos.map((logo) => {
        const isVisible = visibleLogos.has(logo.id);
        
        return (
          <div
            key={logo.id}
            style={{
              position: 'absolute',
              left: `${logo.x}%`,
              top: `${logo.y}%`,
              width: logo.size,
              height: logo.size,
              color: isVisible ? logo.color : 'rgba(220, 220, 220, 0.2)',
              transform: 'translate(-50%, -50%)',
              transition: 'color 0.6s ease-out, filter 0.6s ease-out',
              filter: isVisible ? 'grayscale(0%)' : 'grayscale(100%) brightness(1.8)',
            }}
          >
            {logo.icon}
          </div>
        );
      })}
    </div>
  );
}
